```php
require \_\_DIR\_\_ . "/vendor/autoload.php";
use Location\Coordinate;
use Location\Distance\Vincenty;

class TSP
{
 /\*\*
 \* @var Vincenty
 \*/
 private $calculator;
 /\*\*
 \* @var Coordinate[]
 \*/
 private $points;

 /\*\*
 \* TSP constructor.
 \* @param Coordinate[] $points
 \*/
 public function \_\_construct(array $points)
 {
 $this->points = $points;
 $this->calculator = new Vincenty();
 }

 /\*\*
 \* Generate all permutations of the given items
 \* @param array $items
 \* @param array $perms
 \* @return array
 \*/
 private function permutations(array $items, $perms = [])
 {
 static $allPerms = [];

 if (empty($items)) {
 $allPerms[] = $perms;
 } else {
 for ($i = count($items) - 1; $i >= 0; --$i) {
 $newitems = $items;
 $newperms = $perms;
 list($foo) = array\_splice($newitems, $i, 1);
 array\_unshift($newperms, $foo);
 $this->permutations($newitems, $newperms);
 }
 }
 return $allPerms;
 }

 /\*\*
 \* Find the shortest route
 \*/
 public function solve()
 {
 $shortestDistance = INF;
 $shortestRoute = [];

 // Generate all possible routes
 $routes = $this->permutations($this->points);
 foreach ($routes as $route) {
 // Calculate the distance of the current route
 $distance = 0;
 for ($i = 0; $i < count($route) - 1; $i++) {
 $distance += $this->calculator->getDistance(
 $route[$i],
 $route[$i + 1]
 );
 }
 // Check if the current route is shorter than the previous shortest route
 if ($distance < $shortestDistance) {
 $shortestDistance = $distance;
 $shortestRoute = $route;
 }
 }

 $shortestRouteString = "";
 foreach ($shortestRoute as $coordinate) {
 $shortestRouteString .= sprintf(
 "(%F, %F) -> ",
 $coordinate->getLat(),
 $coordinate->getLng()
 );
 }
 $shortestRouteString = rtrim($shortestRouteString, " -> ");

 echo "Shortest distance: " . $shortestDistance . " meters\n";
 echo "Shortest route: " . $shortestRouteString . "\n";
 }
}
```

