TRANSLATION\_FILE\_PATH = os.path.join(os.path.dirname(\_\_file\_\_), "../translations.json")
PAYLOAD\_FOLDER\_PATH = os.path.abspath(os.path.join(os.path.dirname(\_\_file\_\_), "../payloads"))
class BaseSlashCommand:
 client = DiscordClient()
 translator = Translator(LocaleEnum.ENGLISH.value, TRANSLATION\_FILE\_PATH)

 def \_\_init\_\_(self, command\_name):
 self.command\_name = command\_name
 self.payload = None

 def get\_payload(self):
 payload\_file\_path = os.path.join(PAYLOAD\_FOLDER\_PATH, f"{self.command\_name}.json")
 with open(payload\_file\_path, constants.READ) as f:
 self.payload = json.loads(f.read())
 return self.payload

 def register(self):
 payload = self.get\_payload()
 translated\_payload = self.translator.translate(payload)
 response = self.client.register\_slash\_command(slash\_command\_payload=translated\_payload)
 return response.get(labels.ID)
