def syncJobWithMetadata(Map jobMetadata, String nomadAddr, String nomadToken, boolean dryRun) {
 // Regions for which running Nomad jobs are allowed
 Set whitelistRegions = ["us-east"]
 def jobName = jobMetadata.nomad\_job\_name
 def jobRegion = jobMetadata.region
 if (!whitelistRegions.contains(jobRegion)) {
 echo "[INFO] Skip running ${jobName} since region is: ${jobRegion}"
 return
 }
 def tier = jobMetadata.tier
 def long\_tier = jobMetadata.long\_tier
 def jobspecHcl = sh(script: "ruby ${pwd()}/render\_template.rb ${jobName} ${tier} ${long\_tier}", returnStdout: true)
 def parseHclRequestBodyJson = groovy.json.JsonOutput.toJson(['Canonicalize': true, 'JobHCL': jobspecHcl])
 def parseHclResponse = httpRequest url: "${nomadAddr}/v1/jobs/parse",
 httpMode: 'POST',
 requestBody: parseHclRequestBodyJson,
 validResponseCodes: '100:599'
 if (parseHclResponse.status != 200) {
 echo "[DEBUG] request body: \n${parseHclRequestBodyJson}"
 error "[ERROR] Failed to parse [${jobName}] HCL: response code ${parseHclResponse.status} with body: ${parseHclResponse.content}"
 }
 def jobspecJson = parseHclResponse.content
 def planRequestBodyJson = "{\"Diff\": true, \"Job\": ${jobspecJson}}"
 def needToRunJob = true
 // TODO: revisit retry and skip logic after Nomad upgrade.
 //
 // There is a Nomad bug https://github.com/hashicorp/nomad/issues/8097 in versions 10.x and above,
 // Which leads to failed Plan API calls from time to time for some cases so retry may fix a subset of problems.
 // However if a problem happens for the periodic job - retry does no help.
 // To workaround this we simply can skip "needToRunJob" calculation and force job run.
 def planResponse = retryHttpRequestIfNon200(
 "calculate `needToRunJob` flag using Plan API for `${jobName}`",
 "force `needToRunJob = true`") { ->
 httpRequest(
 url: "${nomadAddr}/v1/job/${jobName}/plan?region=${jobRegion}",
 httpMode: 'POST',
 customHeaders: [[name: 'X-Nomad-Token', value: nomadToken, maskValue: true]],
 requestBody: planRequestBodyJson,
 validResponseCodes: '100:599')
 }
 if (planResponse.status == 200) {
 def planOutput = readJSON(text: planResponse.content)
 needToRunJob = checkIfJobRunIsNeeded(
 jobName,
 jobMetadata,
 planOutput,
 { ->
 response = httpRequest url: "${nomadAddr}/v1/job/${jobName}?region=${jobRegion}",
 customHeaders: [[name: 'X-Nomad-Token', value: nomadToken, maskValue: true]],
 validResponseCodes: '100:599'
 if (response.status != 200) {
 error "[ERROR] Failed to check for Nomad job: response code ${response.status} with body: ${response.content}"
 }
 return response.content
 },
 { jobStateOutput ->
 return readJSON(text: jobStateOutput)
 }
 )
 }
 if (!needToRunJob) {
 echo "[INFO] Skipping running ${jobName} since job run is not required"
 return
 }
 if (dryRun) {
 echo "[INFO] Running ${jobName}... (DRY-RUN)"
 echo "[INFO] Ran ${jobName} (DRY-RUN)"
 return
 }
 echo "[INFO] Running ${jobName}..."
 def runJobRequestBodyJson = "{\"Job\": ${jobspecJson}}"
 response = httpRequest url: "${nomadAddr}/v1/job/${jobName}?region=${jobRegion}",
 httpMode: 'POST',
 customHeaders: [[name: 'X-Nomad-Token', value: nomadToken, maskValue: true]],
 requestBody: runJobRequestBodyJson,
 validResponseCodes: '100:599'
 if (response.status != 200) {
 error "[ERROR] Failed to run Nomad job: response code ${response.status} with body: ${response.content}"
 }
 echo "[INFO] Ran ${jobName}"
}

