background.js:
chrome.commands.onCommand.addListener((command) => {
 if (command === 'assign\_priority' || command === 'sort\_tabs') {
 chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
 const activeTab = tabs[0];
 chrome.scripting.executeScript(
 {
 target: { tabId: activeTab.id },
 files: ['content.js'],
 },
 () => {
 chrome.tabs.sendMessage(activeTab.id, { action: command });
 }
 );
 });
 }
});

chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
 if (message.action === 'assign\_priority') {
 assignPriority(sender.tab, message.priority, message.timestamp);
 } else if (message.action === 'sort\_tabs') {
 sortTabs();
 }
});

function assignPriority(tab, priority, timestamp) {
 const priorityData = {
 level: priority,
 timestamp: timestamp,
 };

 chrome.storage.sync.set({ [`tab-${tab.id}`]: priorityData });
}

function sortTabs() {
 chrome.tabs.query({ currentWindow: true }, (tabs) => {
 const tabPriorities = tabs.map((tab) => {
 return new Promise((resolve) => {
 chrome.storage.sync.get([`tab-${tab.id}`], (result) => {
 const priorityData = result[`tab-${tab.id}`] || {
 level: null,
 timestamp: null,
 };
 resolve({ tabId: tab.id, ...priorityData });
 });
 });
 });

 Promise.all(tabPriorities).then((priorities) => {
 reorderTabs(priorities);
 });
 });
}

function reorderTabs(tabPriorities) {
 tabPriorities.sort((a, b) => {
 if (a.level === null && b.level !== null) return 1;
 if (a.level !== null && b.level === null) return -1;
 if (a.level === null && b.level === null) return 0;

 if (a.level !== b.level) {
 return a.level - b.level;
 } else {
 return a.timestamp - b.timestamp;
 }
 });

 for (let i = 0; i < tabPriorities.length; i++) {
 chrome.tabs.move(tabPriorities[i].tabId, { index: i });
 }

 chrome.tabs.update(tabPriorities[0].tabId, { active: true });
}

