I am writing a conformance test (similar to ESLint) in TypeScript for detecting when a user does not use `rel="noopener"` when using `window.open`. The issue this causes is breaking the bfcache integrity in the browser. Some more details here:

```
# Avoid window.opener references

In some browsers (including Chromium-based browsers) if a page was opened using window.open() or (in Chromium-based browsers prior to version 88) from a link with target=\_blank—without specifying rel="noopener"—then the opening page will have a reference to the window object of the opened page.

In addition to being a security risk, a page with a non-null window.opener reference cannot safely be put into the bfcache because that could break any pages attempting to access it.

As a result, it's best to avoid creating window.opener references by using rel="noopener" whenever possible. If your site requires opening a window and controlling it through window.postMessage() or directly referencing the window object, neither the opened window nor the opener will be eligible for bfcache.
```

Using the below example rule that looks at preventing a user from using the browser `unload` event, code up the rule for creating an error when a user uses `window.open` without `rel="noopener"`:

---
import { stripIndents } from 'common-tags';
import type { AST } from '@typescript-eslint/typescript-estree';
import {
 AST\_NODE\_TYPES,
 simpleTraverse,
} from '@typescript-eslint/typescript-estree';
import type { ConformanceError } from '../conformance-error';
import type { ProjectData } from '../project-data';
import { convertPositionToRange } from '../utils/convert-position-to-range';

const TEST\_NAME = 'BFCACHE\_INTEGRITY\_NO\_UNLOAD\_LISTENERS';

const ERROR\_MESSAGE = stripIndents`
 The \`unload\` event does not fire reliably and listening for it can prevent browser optimizations like the Back-Forward Cache (bfcache).

 Consider using the \`pagehide\`, \`visibilitychange\`, or \`beforeunload\` events instead.

 See https://web.dev/bfcache for more information.
`;

export function noUnloadListeners(
 projectData: ProjectData,
 filePath: string,
 ast: AST<{
 filePath: string;
 loc: true;
 range: false;
 }>,
): ConformanceError[] {
 const conformanceConfig = projectData.getConformanceConfig();
 if (!conformanceConfig.isTestEnabled(TEST\_NAME)) return [];

 const workspaceName = projectData.getWorkspaceName();
 const errors: ConformanceError[] = [];

 simpleTraverse(ast, {
 // Detect `window.onunload =` assignments.
 AssignmentExpression(node, \_parent) {
 if (node.type !== AST\_NODE\_TYPES.AssignmentExpression) return;

 const { left } = node;
 if (left.type !== AST\_NODE\_TYPES.MemberExpression) return;

 const { object, property } = left;
 if (object.type !== AST\_NODE\_TYPES.Identifier) return;
 if (object.name !== 'window') return;
 if (property.type !== AST\_NODE\_TYPES.Identifier) return;
 if (property.name !== 'onunload') return;

 errors.push({
 testName: TEST\_NAME,
 location: {
 workspace: workspaceName,
 filePath,
 range: convertPositionToRange(node.loc),
 },
 message: ERROR\_MESSAGE,
 });
 },
 // Detect `window.addEventListener('unload')` calls.
 CallExpression(node, \_parent) {
 if (node.type !== AST\_NODE\_TYPES.CallExpression) return;

 const { callee } = node;
 if (callee.type !== AST\_NODE\_TYPES.MemberExpression) return;

 const { object, property } = callee;
 if (object.type !== AST\_NODE\_TYPES.Identifier) return;
 if (object.name !== 'window') return;
 if (property.type !== AST\_NODE\_TYPES.Identifier) return;
 if (property.name !== 'addEventListener') return;

 const [eventTypeNode] = node.arguments;
 if (eventTypeNode?.type !== AST\_NODE\_TYPES.Literal) return;
 if (eventTypeNode.value !== 'unload') return;

 errors.push({
 testName: TEST\_NAME,
 location: {
 workspace: workspaceName,
 filePath,
 range: convertPositionToRange(node.loc),
 },
 message: ERROR\_MESSAGE,
 });
 },
 });

 return errors;
}
