import requests
from bs4 import BeautifulSoup
from urllib.parse import urlparse, urljoin
import time

# Function to get all the internal links of a page
def get\_internal\_links(url):
 internal\_links = set()
 parsed\_url = urlparse(url)
 domain = parsed\_url.netloc
 path = parsed\_url.path

 # Make a request to the URL
 response = requests.get(url)

 # If the response is successful, parse the page
 if response.status\_code == 200:
 soup = BeautifulSoup(response.content, 'html.parser')
 # Find all the links on the page
 links = soup.find\_all('a')
 for link in links:
 href = link.get('href')
 # If the link is internal, add it to the set of internal links
 if href:
 parsed\_href = urlparse(href)
 href\_domain = parsed\_href.netloc
 href\_path = parsed\_href.path
 if href\_domain == domain or not href\_domain:
 href = urljoin(url, href\_path)
 if href.startswith('http'):
 internal\_links.add(href)
 return internal\_links

# Function to crawl a website
def crawl(url, max\_depth):
 visited = set()
 queue = [(url, 0)]
 passed\_urls = set()
 failed\_urls = set()
 loop\_count = 0

 while queue:
 url, depth = queue.pop(0)
 # If we've reached the maximum depth, skip this URL
 if depth > max\_depth:
 continue
 # If we've already visited this URL, skip it
 if url in visited:
 continue
 visited.add(url)
 # Get all the internal links on this page
 internal\_links = get\_internal\_links(url)
 # Add the internal links to the queue
 for link in internal\_links:
 queue.append((link, depth+1))
 # Check if the URL is valid and add it to the appropriate set
 loop\_count += 1
 print(f"Loop {loop\_count}: {url}")
 time.sleep(1)
 response = requests.get(url)
 if response.status\_code == 200:
 passed\_urls.add(url)
 else:
 failed\_urls.add(url)

 return passed\_urls, failed\_urls

# Example usage
if \_\_name\_\_ == '\_\_main\_\_':
 url = input("Enter the URL to scrape: ")
 max\_depth = int(input("Enter the maximum depth to crawl: "))
 passed\_urls, failed\_urls = crawl(url, max\_depth)
 print("Passed URLs:")
 for url in passed\_urls:
 print(url)
 print("Failed URLs:")
 for url in failed\_urls:
 print(url)

