impl<'a> Tokenizer<'a> {
 pub fn new(input: &'a str) -> Self {
 Tokenizer {
 input,
 chars: input.char\_indices(),
 }
 }

 fn next\_char(&mut self) -> Option<(usize, char)> {
 self.chars.next()
 }

 fn peek\_char(&mut self) -> Option {
 self.chars.clone().next().map(|(\_, c)| c)
 } 

 fn skip\_whitespace(&mut self) {
 while let Some((\_, c)) = self.next\_char() {
 if !c.is\_whitespace() {
 break;
 }
 }
 }

 // New helper method to check if the current position is a valid token delimiter
 fn is\_at\_delimiter(&self, idx: usize) -> bool {
 self.input.get(idx..).map\_or(true, |s| {
 s.starts\_with(|c: char| c.is\_whitespace() || c.is\_ascii\_punctuation())
 })
 }

 fn parse\_number(&mut self) -> Option {
 let start\_idx = self.chars.clone().next().unwrap().0; // Get the index of the first character
 let mut end\_idx = start\_idx;
 let mut decimal\_point\_found = false;

 while let Some((idx, c)) = self.next\_char() {
 if c == '.' {
 if decimal\_point\_found {
 // We've already seen a decimal point, so this is an invalid number.
 return None;
 }
 decimal\_point\_found = true;
 } else if !c.is\_digit(10) {
 break;
 }
 end\_idx = idx + 1;
 }

 let number\_str = &self.input[start\_idx..end\_idx];
 let number = number\_str.parse::().ok()?;

 Some(Token::Number(number))
 }

 fn parse\_string(&mut self) -> Option {
 let mut string = String::new();
 let mut escaped = false;

 while let Some((\_, c)) = self.next\_char() {
 if escaped {
 string.push(c);
 escaped = false;
 } else if c == '\\' {
 escaped = true;
 } else if c == '"' {
 return Some(Token::String(string));
 } else {
 string.push(c);
 }
 }

 None
 }

 fn parse\_boolean(&mut self, start\_idx: usize) -> Option {
 let end\_idx = start\_idx + 4;
 let substr = &self.input[start\_idx..end\_idx];

 if substr == "true" {
 self.set\_position(end\_idx);
 Some(Token::Boolean(true))
 } else {
 let end\_idx = start\_idx + 5;
 let substr = &self.input[start\_idx..end\_idx];
 if substr == "false" {
 self.set\_position(end\_idx);
 Some(Token::Boolean(false))
 } else {
 None
 }
 }
 }

 fn parse\_identifier(&mut self) -> Option {
 let start\_idx = self.chars.clone().next().unwrap().0;
 let end\_idx = self.input[start\_idx..]
 .find(|c: char| !c.is\_alphanumeric() && c != '\_')
 .map(|pos| start\_idx + pos)
 .unwrap\_or\_else(|| self.input.len());

 let identifier = self.input[start\_idx..end\_idx].to\_owned();
 self.input = &self.input[end\_idx..];

 Some(Token::Identifier(identifier))
 }

 fn parse\_keyword(&mut self) -> Option {
 let token = match &\*self.input {
 \_ if self.input.starts\_with("if") && self.is\_at\_delimiter(2) => Token::If,
 \_ if self.input.starts\_with("else") && self.is\_at\_delimiter(4) => Token::Else,
 \_ if self.input.starts\_with("while") && self.is\_at\_delimiter(5) => Token::While,
 \_ if self.input.starts\_with("for") && self.is\_at\_delimiter(3) => Token::For,
 \_ if self.input.starts\_with("function") && self.is\_at\_delimiter(8) => Token::Function,
 \_ if self.input.starts\_with("class") && self.is\_at\_delimiter(5) => Token::Class,
 \_ if self.input.starts\_with("import") && self.is\_at\_delimiter(6) => Token::Import,
 \_ if self.input.starts\_with("return") && self.is\_at\_delimiter(6) => Token::Return,
 // Add other keywords as needed
 \_ => return None,
 };

 let token\_len = token.to\_string().len();
 self.input = &self.input[token\_len..];
 Some(token)
 }

 fn parse\_operator(&mut self) -> Option {
 let token = match self.input.chars().next()? {
 '+' => Some(Token::Plus),
 '-' => Some(Token::Minus),
 '\*' => Some(Token::Star),
 '/' => Some(Token::Slash),
 // Add other operators as needed
 \_ => return None,
 };

 if let Some(token) = &token {
 let token\_len = token.to\_string().len();
 if self.input[token\_len..]
 .starts\_with(|c: char| c.is\_whitespace() || c.is\_ascii\_punctuation())
 {
 self.input = &self.input[token\_len..];
 return Some(token.clone());
 }
 }
 None
 }

 fn parse\_delimiter(&mut self) -> Option {
 let token = match self.input.chars().next()? {
 '(' => Token::LParen,
 ')' => Token::RParen,
 '{' => Token::LBrace,
 '}' => Token::RBrace,
 ',' => Token::Comma,
 ':' => Token::Colon,
 ';' => Token::Semicolon,
 '=' => Token::Equals,
 '>' if self.input.starts\_with("->") => Token::Arrow,
 \_ => return None,
 };

 let token\_len = token.to\_string().len();
 self.input = &self.input[token\_len..];
 Some(token)
 }

 pub fn next\_token(&mut self) -> Option {
 self.skip\_whitespace();

 let (idx, c) = self.next\_char()?;

 let token = if c.is\_digit(10) {
 self.parse\_number()
 } else if c == '\"' {
 self.parse\_string()
 } else if c.is\_alphabetic() {
 let token = self.parse\_identifier()?;

 // Try to parse a boolean literal
 self.parse\_boolean(idx)
 // If it's not a boolean, try to parse a keyword
 .or\_else(|| self.parse\_keyword())
 // If it's not a keyword, return the identifier token
 .or(Some(token))
 } else {
 self.parse\_operator().or\_else(|| self.parse\_delimiter())
 };

 token
 }
}

