Epicycloid Primitive:
An epicycloid is a curve traced by a point on the circumference of a circle rolling around the outside of another circle without slipping. It can generate a wide range of shapes, including stars and polygons.
glsl
Copy code
vec2 epicycloid(float t, float a, float b, float h) {
 return vec2((a + b) \* cos(t) - h \* cos((a + b) \* t / b),
 (a + b) \* sin(t) - h \* sin((a + b) \* t / b));
}

float epicycloidSDF(vec3 p, float a, float b, float h, float thickness) {
 float t = atan(p.y, p.x);
 vec2 curvePoint = epicycloid(t, a, b, h);
 return length(p.xy - curvePoint) - thickness;
}
Seashell Primitive:
A seashell shape can be generated by combining a logarithmic spiral with a helix, producing a wide range of natural-looking shell forms.
glsl
Copy code
vec3 seashell(float t, float a, float b, float c, float d) {
 return vec3((a + b \* t) \* cos(t), c \* t, (a + b \* t) \* sin(t)) + d \* vec3(cos(c \* t), 0, sin(c \* t));
}

float seashellSDF(vec3 p, float a, float b, float c, float d, float thickness) {
 float t = atan(p.y, p.x);
 vec3 shellPoint = seashell(t, a, b, c, d);
 return length(p - shellPoint) - thickness;
}
