You are a typescript nextJS developer. You are tasked to write a bunch of API server-side handlers for the following requirements:

1. create a user
2. delete a user
3. update a user's last login time
4. add a new user agent to the user's devices list
5. remove an existing device (based on index) from the user's devices list
6. get the user's information

You are provided with the services functions as follows:

import {
 insertUser,
 deleteUser,
 updateUserLastLoginAt,
 getUserDevices,
 updateUserDevices,
} from '../db/userRepository';
import { generateHashedString } from '../utils';
import IUser from '../../types/user.interface';

const createUser = async (nickname: string): Promise => {
 const now = Date.now();
 const userAgent = navigator.userAgent;
 const recoveryKey = generateHashedString(nickname, now);
 const { data } = await insertUser(nickname, recoveryKey, userAgent);
 return data[0] as IUser;
};

const deleteUserByNicknameAndRecoveryKey = async (
 nickname: string,
 recoveryKey: string
): Promise => {
 await deleteUser(nickname, recoveryKey);
};

const updateLastLoginAt = async (
 nickname: string,
 recoveryKey: string,
 lastLoginAt: number
): Promise => {
 await updateUserLastLoginAt(nickname, recoveryKey, new Date(lastLoginAt));
};

const addDeviceToUser = async (
 nickname: string,
 recoveryKey: string,
 device: string
): Promise => {
 const { data } = await getUserDevices(nickname, recoveryKey);
 const devices = data[0].devices as string[];
 devices.push(device);
 await updateUserDevices(nickname, recoveryKey, devices);
};

const removeDeviceFromUser = async (
 nickname: string,
 recoveryKey: string,
 deviceIndex: number
): Promise => {
 const { data } = await getUserDevices(nickname, recoveryKey);
 const devices = data[0].devices as string[];
 devices.splice(deviceIndex, 1);
 await updateUserDevices(nickname, recoveryKey, devices);
};

const getUserByNicknameAndRecoveryKey = async (
 nickname: string,
 recoveryKey: string
): Promise => {
 const { data } = await getUserDevices(nickname, recoveryKey);
 if (data.length === 0) {
 return null;
 }
 return data[0] as IUser;
};

export {
 createUser,
 getUserByNicknameAndRecoveryKey,
 updateLastLoginAt,
 removeDeviceFromUser,
 addDeviceToUser,
 deleteUserByNicknameAndRecoveryKey,
};

And you are provided with the user interface as well:

export default interface IUser {
 nickname: string;
 recoveryKey: string;
 createdAt: number;
 lastLoginAt: number;
 devices: string[];
}

